class Solution {
public:
    int findMaxK(vector<int>& nums) {
        unordered_map<int, int> num_count;
        int max_k = -1;

        for (int num : nums) {
            if (num < 0) {
                num_count[-num]++;
                max_k = max(max_k, -num);
            }
        }

        return max_k;
    }
};
